import { createLinterRuleTester, LinterRuleTester } from "@typespec/compiler/testing";
import { beforeEach, describe, it } from "vitest";
import { Tester } from "../testing/test-host.js";
import { invariantProjectedOncePerOpRule } from "./invariant-projected-once-per-op.rule.js";

const ENTITY = `
  namespace Products.MyProduct.Entities.Task {
    @entity
    model Task { id: string; }
  }
  using Products.MyProduct.Entities.Task;
`;

const FEATURE_WITH_INV = `
  @feature
  namespace Products.MyProduct.Features.Lifecycle {
    @invariant(#{ predicate: "A {@Task} has an id.", why: "Reason." })
    op task_has_id(): void;
  }
`;

// a10n:blueprint:test-steps Components.A10nBlueprintTypespecSdk.Operations.rule_invariant_projected_once_per_op
describe("invariant-projected-once-per-op rule", () => {
  let ruleTester: LinterRuleTester;

  beforeEach(async () => {
    const runner = await Tester.createInstance();
    ruleTester = createLinterRuleTester(runner, invariantProjectedOncePerOpRule, "@a10n/blueprint-typespec");
  });

  // ─── valid ────────────────────────────────────────────────────────────────

  describe("valid", () => {
    // a10n:blueprint:test-steps Components.A10nBlueprintTypespecSdk.Operations.rule_invariant_projected_once_per_op
    // a10n:blueprint Components.A10nBlueprintTypespecSdk.Tests.Rules.T024.T024_01
    it("each invariant listed exactly once passes", async () => {
      await ruleTester
        .expect(`
          ${ENTITY}
          ${FEATURE_WITH_INV}
          @component(#{ type: ComponentType.Agent })
          namespace Components.MyAgent {
            @tool(#{ sequential: false })
            @projects(Products.MyProduct.Features.Lifecycle.task_has_id)
            op do_task(): void;
          }
        `)
        .toBeValid();
    });

    // a10n:blueprint Components.A10nBlueprintTypespecSdk.Tests.Rules.T024.T024_02
    it("op without @projects is not flagged", async () => {
      await ruleTester
        .expect(`
          ${ENTITY}
          ${FEATURE_WITH_INV}
          @component(#{ type: ComponentType.Agent })
          namespace Components.MyAgent {
            @tool(#{ sequential: false })
            op do_task(): void;
          }
        `)
        .toBeValid();
    });
  });

  // ─── invalid ──────────────────────────────────────────────────────────────

  describe("invalid", () => {
    // a10n:blueprint:test Components.A10nBlueprintTypespecSdk.Operations.rule_invariant_projected_once_per_op:Products.A10nBlueprintEngine.Features.InvariantProjection.invariant_projected_once:must
    it("same invariant listed twice emits warning", async () => {
      await ruleTester
        .expect(`
          ${ENTITY}
          ${FEATURE_WITH_INV}
          @component(#{ type: ComponentType.Agent })
          namespace Components.MyAgent {
            // a10n:blueprint:ignore
            @tool(#{ sequential: false })
            @projects(
              Products.MyProduct.Features.Lifecycle.task_has_id,
              Products.MyProduct.Features.Lifecycle.task_has_id
            )
            op do_task(): void;
          }
        `)
        .toEmitDiagnostics({
          code: "@a10n/blueprint-typespec/invariant-projected-once-per-op",
          message: /task_has_id/,
        });
    });

    // a10n:blueprint Components.A10nBlueprintTypespecSdk.Tests.Rules.T024.T024_04
    it("message includes the op FQN", async () => {
      await ruleTester
        .expect(`
          ${ENTITY}
          ${FEATURE_WITH_INV}
          @component(#{ type: ComponentType.Agent })
          namespace Components.MyAgent {
            // a10n:blueprint:ignore
            @tool(#{ sequential: false })
            @projects(
              Products.MyProduct.Features.Lifecycle.task_has_id,
              Products.MyProduct.Features.Lifecycle.task_has_id
            )
            op do_task(): void;
          }
        `)
        .toEmitDiagnostics({
          code: "@a10n/blueprint-typespec/invariant-projected-once-per-op",
          message: /Components\.MyAgent\.do_task/,
        });
    });
  });
});
